import React, { useState, useRef, useEffect } from 'react';
import { Search, X, Filter, Clock, TrendingUp } from 'lucide-react';
import { useDebounce } from '../hooks/useDebounce';
import { validateSearchQuery, sanitizeInput } from '../utils/validation';

const AdvancedSearchBar = ({ 
  onSearch, 
  placeholder = "Search courses...", 
  suggestions = [],
  recentSearches = [],
  onRecentSearch,
  className = ""
}) => {
  const [query, setQuery] = useState('');
  const [isOpen, setIsOpen] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [filteredSuggestions, setFilteredSuggestions] = useState([]);
  const inputRef = useRef(null);
  const containerRef = useRef(null);

  const debouncedQuery = useDebounce(query, 300);

  useEffect(() => {
    if (validateSearchQuery(debouncedQuery)) {
      onSearch(debouncedQuery);
    }
  }, [debouncedQuery, onSearch]);

  useEffect(() => {
    if (query.length > 0) {
      const filtered = suggestions.filter(suggestion =>
        suggestion.toLowerCase().includes(query.toLowerCase())
      ).slice(0, 5);
      setFilteredSuggestions(filtered);
      setIsOpen(true);
    } else {
      setFilteredSuggestions([]);
      setIsOpen(false);
    }
  }, [query, suggestions]);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (containerRef.current && !containerRef.current.contains(event.target)) {
        setIsOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleInputChange = (e) => {
    const value = sanitizeInput(e.target.value);
    setQuery(value);
    setSelectedIndex(-1);
  };

  const handleKeyDown = (e) => {
    const totalItems = filteredSuggestions.length + (recentSearches.length > 0 ? recentSearches.length : 0);

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        setSelectedIndex(prev => (prev < totalItems - 1 ? prev + 1 : -1));
        break;
      case 'ArrowUp':
        e.preventDefault();
        setSelectedIndex(prev => (prev > -1 ? prev - 1 : totalItems - 1));
        break;
      case 'Enter':
        e.preventDefault();
        if (selectedIndex >= 0) {
          const allItems = [...filteredSuggestions, ...recentSearches];
          const selectedItem = allItems[selectedIndex];
          handleSelectSuggestion(selectedItem);
        } else if (query.trim()) {
          handleSearch();
        }
        break;
      case 'Escape':
        setIsOpen(false);
        inputRef.current?.blur();
        break;
    }
  };

  const handleSelectSuggestion = (suggestion) => {
    setQuery(suggestion);
    setIsOpen(false);
    onSearch(suggestion);
    if (onRecentSearch) {
      onRecentSearch(suggestion);
    }
  };

  const handleSearch = () => {
    if (validateSearchQuery(query)) {
      onSearch(query);
      setIsOpen(false);
      if (onRecentSearch) {
        onRecentSearch(query);
      }
    }
  };

  const clearSearch = () => {
    setQuery('');
    onSearch('');
    inputRef.current?.focus();
  };

  const handleFocus = () => {
    if (query.length > 0 || recentSearches.length > 0) {
      setIsOpen(true);
    }
  };

  return (
    <div ref={containerRef} className={`relative ${className}`}>
      <div className="relative">
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
          <Search className="h-5 w-5 text-gray-400" />
        </div>

        <input
          ref={inputRef}
          type="text"
          value={query}
          onChange={handleInputChange}
          onKeyDown={handleKeyDown}
          onFocus={handleFocus}
          placeholder={placeholder}
          className="
            w-full pl-10 pr-12 py-3 
            bg-white border border-gray-300 rounded-xl
            focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent
            placeholder-gray-500 text-gray-900
            transition-all duration-200
            shadow-sm hover:shadow-md
          "
          autoComplete="off"
        />

        {query && (
          <button
            onClick={clearSearch}
            className="absolute inset-y-0 right-0 pr-3 flex items-center text-gray-400 hover:text-gray-600 transition-colors"
          >
            <X className="h-5 w-5" />
          </button>
        )}
      </div>

      {isOpen && (
        <div className="absolute top-full left-0 right-0 mt-2 bg-white border border-gray-200 rounded-xl shadow-xl z-50 max-h-80 overflow-y-auto">
          {/* Recent Searches */}
          {query.length === 0 && recentSearches.length > 0 && (
            <div className="p-3 border-b border-gray-100">
              <div className="flex items-center text-xs font-semibold text-gray-500 mb-2">
                <Clock className="w-3 h-3 mr-1" />
                Recent Searches
              </div>
              {recentSearches.slice(0, 3).map((search, index) => (
                <button
                  key={index}
                  onClick={() => handleSelectSuggestion(search)}
                  className={`
                    w-full text-left px-3 py-2 rounded-lg text-sm
                    hover:bg-gray-50 transition-colors
                    ${selectedIndex === index ? 'bg-blue-50 text-blue-700' : 'text-gray-700'}
                  `}
                >
                  {search}
                </button>
              ))}
            </div>
          )}

          {/* Suggestions */}
          {filteredSuggestions.length > 0 && (
            <div className="p-3">
              <div className="flex items-center text-xs font-semibold text-gray-500 mb-2">
                <TrendingUp className="w-3 h-3 mr-1" />
                Suggestions
              </div>
              {filteredSuggestions.map((suggestion, index) => {
                const adjustedIndex = recentSearches.length > 0 && query.length === 0 
                  ? index + recentSearches.length 
                  : index;

                return (
                  <button
                    key={index}
                    onClick={() => handleSelectSuggestion(suggestion)}
                    className={`
                      w-full text-left px-3 py-2 rounded-lg text-sm
                      hover:bg-gray-50 transition-colors
                      ${selectedIndex === adjustedIndex ? 'bg-blue-50 text-blue-700' : 'text-gray-700'}
                    `}
                  >
                    <span className="font-medium">
                      {suggestion.substring(0, query.length)}
                    </span>
                    <span>
                      {suggestion.substring(query.length)}
                    </span>
                  </button>
                );
              })}
            </div>
          )}

          {/* No Results */}
          {query.length > 0 && filteredSuggestions.length === 0 && (
            <div className="p-4 text-center text-gray-500 text-sm">
              No suggestions found for "{query}"
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default AdvancedSearchBar;
